 16	interface OutputEnvelope {
 17	  command: string;
 18	  version: 1;
 19	  status: CliStatus;
 20	  outcome: string;
 21	  result?: unknown;
 22	  errors: CliError[];
 23	  warnings: string[];
 24	  artifacts: CliArtifactRef[];
 25	  startedAt: string;
 26	  finishedAt: string;
 27	}
 28	
 29	function renderHumanSummary(envelope: OutputEnvelope) {
 30	  if (
 31	    typeof envelope.result !== "object" ||
 32	    envelope.result === null ||
 33	    !("story" in envelope.result) ||
 34	    !("verifierResults" in envelope.result)
 35	  ) {
 36	    return `story-verify: ${envelope.outcome}`;
 37	  }
 38	
 39	  const result = envelope.result as {
 40	    story: {
 41	      id: string;
 42	    };
 43	    verifierResults: unknown[];
 44	  };
 45	  return [
 46	    `story-verify: ${envelope.outcome}`,
 47	    `story: ${result.story.id}`,
 48	    `verifiers: ${result.verifierResults.length}`,
 49	  ].join("\n");
 50	}
 51	
 52	function emitOutput(params: {
 53	  envelope: OutputEnvelope;
 54	  json: boolean;
 55	}) {
 56	  if (params.json) {
 57	    console.log(JSON.stringify(params.envelope));
 58	    return;
 59	  }
 60	
 61	  console.log(renderHumanSummary(params.envelope));
 62	}
