 64	export default defineCommand({
 65	  meta: {
 66	    name: "story-verify",
 67	    description: "Launch a fresh verifier batch for one story.",
 68	  },
 69	  args: {
 70	    "spec-pack-root": {
 71	      type: "string",
 72	      description: "Absolute or relative path to the spec-pack root",
 73	      required: true,
 74	    },
 75	    "story-id": {
 76	      type: "string",
 77	      description: "The story id to verify",
 78	      required: true,
 79	    },
 80	    config: {
 81	      type: "string",
 82	      description: "Explicit run-config file relative to the spec-pack root",
 83	    },
 84	    json: {
 85	      type: "boolean",
 86	      description: "Emit the structured JSON envelope on stdout",
 87	    },
 88	  },
 89	  async run({ args }) {
 90	    const startedAt = new Date().toISOString();
 91	    const artifactPath = await nextGroupedArtifactPath(
 92	      args["spec-pack-root"],
 93	      args["story-id"],
 94	      "verify-batch"
 95	    );
 96	
 97	    try {
 98	      const outcome = await runStoryVerify({
 99	        specPackRoot: args["spec-pack-root"],
100	        storyId: args["story-id"],
101	        configPath: args.config,
102	        env: process.env,
103	      });
104	      const envelope = cliResultEnvelopeSchema(
105	        storyVerifierBatchResultSchema
106	      ).parse(
107	        createResultEnvelope({
108	          command: "story-verify",
109	          outcome: outcome.outcome,
110	          result: outcome.result,
111	          errors: outcome.errors,
112	          warnings: outcome.warnings,
113	          artifacts: [
114	            {
115	              kind: "result-envelope",
116	              path: artifactPath,
117	            },
118	          ],
119	          startedAt,
120	          finishedAt: new Date().toISOString(),
121	        })
122	      );
123	
124	      await writeJsonArtifact(artifactPath, envelope);
125	      emitOutput({
126	        envelope,
127	        json: Boolean(args.json),
128	      });
129	      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
130	    } catch (error) {
131	      const envelope: OutputEnvelope = createResultEnvelope({
132	        command: "story-verify",
133	        outcome:
134	          error instanceof ZodError ||
135	          (error instanceof Error &&
136	            error.message.toLowerCase().includes("config"))
137	            ? "block"
138	            : "error",
139	        errors: [
140	          {
141	            code:
142	              error instanceof ZodError ||
143	              (error instanceof Error &&
144	                error.message.toLowerCase().includes("config"))
145	                ? "INVALID_RUN_CONFIG"
146	                : "UNEXPECTED_ERROR",
147	            message: error instanceof Error ? error.message : String(error),
148	          },
149	        ],
150	        artifacts: [
151	          {
152	            kind: "result-envelope",
153	            path: artifactPath,
154	          },
155	        ],
156	        startedAt,
157	        finishedAt: new Date().toISOString(),
158	      });
159	
160	      await writeJsonArtifact(artifactPath, envelope);
161	      emitOutput({
162	        envelope,
163	        json: Boolean(args.json),
164	      });
165	      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
166	    }
167	  },
168	});

