 91	async function prepareStoryVerifyContext(input: {
 92	  specPackRoot: string;
 93	  storyId: string;
 94	  configPath?: string;
 95	}): Promise<PreparedStoryContext | WorkflowFailure> {
 96	  const inspection = await inspectSpecPack(input.specPackRoot);
 97	  if (inspection.status !== "ready") {
 98	    return {
 99	      outcome: "block",
100	      errors: [
101	        blockedError(
102	          "INVALID_SPEC_PACK",
103	          "Spec-pack inspection must be ready before story verification can start.",
104	          inspection.blockers.join("; ") || inspection.notes.join("; ")
105	        ),
106	      ],
107	    };
108	  }
109	
110	  const story = inspection.stories.find((candidate) => candidate.id === input.storyId);
111	  if (!story) {
112	    return {
113	      outcome: "block",
114	      errors: [
115	        blockedError(
116	          "INVALID_SPEC_PACK",
117	          `Story '${input.storyId}' was not found in the resolved story inventory.`
118	        ),
119	      ],
120	    };
121	  }
122	
123	  const config = await loadRunConfig({
124	    specPackRoot: inspection.specPackRoot,
125	    configPath: input.configPath,
126	  });
127	  const gateResolution = await resolveVerificationGates({
128	    specPackRoot: inspection.specPackRoot,
129	  });
130	  if (gateResolution.status !== "ready" || !gateResolution.verificationGates) {
131	    return {
132	      outcome: "block",
133	      errors: gateResolution.errors.length
134	        ? gateResolution.errors
135	        : [
136	            blockedError(
137	              "VERIFICATION_GATE_UNRESOLVED",
138	              "Verification gates must be resolved before story verification can start."
139	            ),
140	          ],
141	    };
142	  }
143	
144	  return {
145	    specPackRoot: inspection.specPackRoot,
146	    story: {
147	      id: story.id,
148	      title: story.title,
149	      path: story.path,
150	    },
151	    verifierPromptInsertPath:
152	      inspection.inserts.customStoryVerifierPromptInsert === "present"
153	        ? join(inspection.specPackRoot, "custom-story-verifier-prompt-insert.md")
154	        : undefined,
155	    gateCommands: {
156	      story: gateResolution.verificationGates.storyGate,
157	      epic: gateResolution.verificationGates.epicGate,
158	    },
159	    paths: {
160	      epicPath: inspection.artifacts.epicPath,
161	      techDesignPath: inspection.artifacts.techDesignPath,
162	      techDesignCompanionPaths: inspection.artifacts.techDesignCompanionPaths,
163	      testPlanPath: inspection.artifacts.testPlanPath,
164	    },
165	    verifiers: [
