202	async function executeVerifier(input: {
203	  provider: ProviderName;
204	  specPackRoot: string;
205	  model: string;
206	  reasoningEffort: string;
207	  prompt: string;
208	  env?: Record<string, string | undefined>;
209	}): Promise<VerifierExecutionSuccess | VerifierExecutionFailure> {
210	  const adapter = createProviderAdapter(input.provider, {
211	    env: input.env,
212	  });
213	  const execution = await adapter.execute({
214	    prompt: input.prompt,
215	    cwd: input.specPackRoot,
216	    model: input.model,
217	    reasoningEffort: input.reasoningEffort,
218	    timeoutMs: 30_000,
219	    resultSchema: providerPayloadSchema,
220	  });
221	
222	  if (execution.exitCode !== 0) {
223	    return {
224	      errors: [
225	        executionFailureError({
226	          provider: input.provider,
227	          stderr: execution.stderr,
228	          errorCode: execution.errorCode,
229	        }),
230	      ],
231	    };
232	  }
233	
234	  if (execution.parseError || !execution.parsedResult) {
235	    return {
236	      errors: [
