300	    case "ready-for-closeout":
301	    case "needs-fixes":
302	    case "needs-more-routing":
303	    case "needs-more-verification":
304	      return "ok";
305	    case "block":
306	      return "blocked";
307	    case "needs-user-decision":
308	    case "needs-human-ruling":
309	      return "needs-user-decision";
310	    case "blocked":
311	      return "blocked";
