325	export function exitCodeForStatus(status: CliStatus, outcome?: string): number {
326	  switch (status) {
327	    case "ok":
328	      return outcome && !zeroExitOutcomes.has(outcome) ? 2 : 0;
329	    case "needs-user-decision":
330	      return 2;
331	    case "blocked":
