 14	async function writeProviderBinary(params: {
 15	  dir: string;
 16	  name: string;
 17	  version: string;
 18	  authStatus?: "authenticated" | "missing";
 19	  authBehavior?: "normal" | "timeout" | "unknown";
 20	  captureCwdPath?: string;
 21	  failureStderr?: string;
 22	  authFailureStderr?: string;
 23	}) {
 24	  const authStatus = params.authStatus ?? "authenticated";
 25	  const scriptPath = join(params.dir, params.name);
 26	  const script = [
 27	    "#!/bin/sh",
 28	    params.captureCwdPath
 29	      ? `printf '%s' \"$PWD\" > "${params.captureCwdPath}"`
 30	      : "",
 31	    'if [ "$1" = "--version" ]; then',
 32	    params.failureStderr
 33	      ? `  echo "${params.failureStderr}" >&2`
 34	      : "",
 35	    `  echo "${params.version}"`,
 36	    "  exit 0",
 37	    "fi",
 38	    'if [ "$1" = "auth" ] && [ "$2" = "status" ]; then',
 39	    params.authBehavior === "timeout"
 40	      ? "  sleep 2"
 41	      : params.authBehavior === "unknown"
 42	        ? `  echo "${params.authFailureStderr ?? "transient provider failure"}" >&2`
 43	        : authStatus === "authenticated"
 44	          ? '  echo "authenticated"'
 45	          : '  echo "missing" >&2',
 46	    params.authBehavior === "timeout"
 47	      ? "  exit 0"
 48	      : params.authBehavior === "unknown"
 49	        ? "  exit 70"
 50	        : authStatus === "authenticated"
 51	          ? "  exit 0"
 52	          : "  exit 1",
 53	    "fi",
 54	    'echo "unexpected invocation" >&2',
 55	    "exit 1",
 56	    "",
 57	  ].join("\n");
 58	  await writeTextFile(scriptPath, script);
 59	  await chmod(scriptPath, 0o755);
 60	}
