297	export async function writeFakeProviderExecutable(params: {
298	  binDir: string;
299	  provider: "claude" | "codex" | "copilot";
300	  responses?: FakeProviderResponse[];
301	  version?: string;
302	  authStatus?: "authenticated" | "missing";
303	  authStdout?: string;
304	  authStderr?: string;
305	}) {
306	  const prefix = params.provider.toUpperCase().replace(/-/g, "_");
307	  const scriptPath = join(params.binDir, params.provider);
308	  const logPath = join(params.binDir, `${params.provider}-invocations.jsonl`);
309	  const responsesPath = join(params.binDir, `${params.provider}-responses.json`);
310	  const cursorPath = join(params.binDir, `${params.provider}-cursor.txt`);
311	
312	  await writeTextFile(
313	    responsesPath,
314	    `${JSON.stringify(params.responses ?? [], null, 2)}\n`
315	  );
316	  await writeTextFile(cursorPath, "0\n");
317	  await writeTextFile(
318	    scriptPath,
319	    [
320	      "#!/usr/bin/env bun",
321	      "import { appendFileSync, existsSync, readFileSync, writeFileSync } from \"node:fs\";",
322	      "import { basename } from \"node:path\";",
323	      "",
324	      "const provider = basename(process.argv[1]);",
325	      "const prefix = provider.toUpperCase().replace(/-/g, \"_\");",
326	      "const envKey = (name) => `${prefix}_${name}`;",
327	      "const args = process.argv.slice(2);",
328	      "const logPath = process.env[envKey(\"LOG_PATH\")];",
329	      "",
330	      "if (logPath) {",
331	      "  appendFileSync(logPath, `${JSON.stringify({ provider, cwd: process.cwd(), args })}\\n`);",
332	      "}",
333	      "",
334	      "if (args.length === 1 && args[0] === \"--version\") {",
335	      "  process.stdout.write(process.env[envKey(\"VERSION\")] ?? `${provider} 1.0.0`);",
336	      "  process.exit(Number(process.env[envKey(\"VERSION_EXIT_CODE\")] ?? 0));",
337	      "}",
338	      "",
339	      "if (args[0] === \"auth\" && args[1] === \"status\") {",
340	      "  const authStatus = process.env[envKey(\"AUTH_STATUS\")] ?? \"authenticated\";",
341	      "  if (authStatus === \"authenticated\") {",
342	      "    process.stdout.write(process.env[envKey(\"AUTH_STDOUT\")] ?? \"authenticated\");",
343	      "    process.exit(0);",
344	      "  }",
345	      "  process.stderr.write(process.env[envKey(\"AUTH_STDERR\")] ?? \"missing\");",
346	      "  process.exit(1);",
347	      "}",
348	      "",
349	      "const responsesPath = process.env[envKey(\"RESPONSES_PATH\")];",
350	      "const cursorPath = process.env[envKey(\"CURSOR_PATH\")];",
351	      "if (!responsesPath || !cursorPath) {",
352	      "  process.stderr.write(\"Missing fake provider response configuration\");",
353	      "  process.exit(1);",
354	      "}",
355	      "",
356	      "const responses = JSON.parse(readFileSync(responsesPath, \"utf8\"));",
357	      "const rawCursor = existsSync(cursorPath) ? readFileSync(cursorPath, \"utf8\").trim() : \"0\";",
358	      "const cursor = Number(rawCursor || \"0\");",
359	      "const response = responses[cursor] ?? responses[responses.length - 1] ?? {",
360	      "  stderr: \"No fake provider response configured\",",
361	      "  exitCode: 1,",
362	      "};",
363	      "writeFileSync(cursorPath, `${cursor + 1}`);",
364	      "if (response.stderr) {",
365	      "  process.stderr.write(response.stderr);",
366	      "}",
367	      "if (response.stdout) {",
368	      "  process.stdout.write(response.stdout);",
369	      "}",
370	      "process.exit(Number(response.exitCode ?? 0));",
371	      "",
372	    ].join("\n")
373	  );
374	  await chmod(scriptPath, 0o755);
375	
376	  return {
377	    logPath,
378	    env: {
379	      [`${prefix}_LOG_PATH`]: logPath,
380	      [`${prefix}_RESPONSES_PATH`]: responsesPath,
381	      [`${prefix}_CURSOR_PATH`]: cursorPath,
382	      [`${prefix}_VERSION`]: params.version ?? `${params.provider} 1.0.0`,
383	      [`${prefix}_AUTH_STATUS`]: params.authStatus ?? "authenticated",
384	      ...(params.authStdout
385	        ? {
386	            [`${prefix}_AUTH_STDOUT`]: params.authStdout,
387	          }
388	        : {}),
389	      ...(params.authStderr
390	        ? {
391	            [`${prefix}_AUTH_STDERR`]: params.authStderr,
392	          }
393	        : {}),
394	    } satisfies Record<string, string>,
395	  };
396	}
